# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, int userId)
{
    var retryCount = 0;
    var maxRetries = 3;
    
    while (retryCount < maxRetries)
    {
        try
        {
            using var context = new EventBookingContext();
            
            var ticket = await context.Tickets
                .FirstOrDefaultAsync(t => t.EventId == eventId && t.UserId == userId);
            
            if (ticket != null)
            {
                var existingQuantity = ticket.Quantity;
                var totalRequested = existingQuantity + quantity;
                
                if (totalRequested > 10)
                {
                    return false;
                }
                
                var availableSeats = await context.EventSeats
                    .Where(es => es.EventId == eventId && es.IsAvailable)
                    .CountAsync();
                
                if (totalRequested > availableSeats)
                {
                    return false;
                }
                
                ticket.Quantity = totalRequested;
                ticket.UpdatedAt = DateTime.UtcNow;
            }
            else
            {
                var availableSeats = await context.EventSeats
                    .Where(es => es.EventId == eventId && es.IsAvailable)
                    .CountAsync();
                
                if (quantity > availableSeats || quantity > 10)
                {
                    return false;
                }
                
                context.Tickets.Add(new Ticket
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    CreatedAt = DateTime.UtcNow,
                    UpdatedAt = DateTime.UtcNow
                });
            }
            
            var updatedSeats = await context.EventSeats
                .Where(es => es.EventId == eventId && es.IsAvailable)
                .Take(quantity)
                .Select(es => es.Id)
                .ToListAsync();
            
            if (updatedSeats.Count != quantity)
            {
                return false;
            }
            
            await context.EventSeats
                .Where(es => updatedSeats.Contains(es.Id))
                .ExecuteUpdateAsync(setters => setters.SetProperty(e => e.IsAvailable, false));
            
            await context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException)
        {
            retryCount++;
            await Task.Delay(100 * retryCount);
        }
        catch (Exception)
        {
            return false;
        }
    }
    
    return false;
}